import { Component } from '@angular/core';
import { Router } from '@angular/router';

@Component({
  selector: 'app-layout',
  templateUrl: './layout.component.html'
})
export class LayoutComponent {
  constructor(private router: Router) {}

  isActive(route: string): boolean {
    return this.router.isActive(route, {
      paths: 'exact',
      queryParams: 'exact',
      fragment: 'ignored',
      matrixParams: 'ignored'
    });
  }

  scrollToTop() {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }
}
<div class="min-h-screen flex flex-col">
  <header class="bg-white shadow-sm sticky top-0 z-50">
    <nav class="container mx-auto px-4 flex items-center justify-between h-16 lg:h-20">
      <div class="flex items-center">
        <a routerLink="/inicio" class="text-2xl font-bold text-blue-600 hover:text-blue-700 transition-colors">
          BOOST AGENCY
        </a>
      </div>
      
      <!-- Desktop Navigation -->
      <div class="hidden lg:flex items-center space-x-8">
        <a routerLink="/inicio" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">Inicio</a>
        <a routerLink="/nosotros" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">Nosotros</a>
        <a routerLink="/servicios" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">Servicios</a>
        <a routerLink="/planes" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">Planes</a>
        <a routerLink="/fundacion" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">Fundación</a>
        <a routerLink="/boostcast" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">BoostCast</a>
        <a routerLink="/tienda" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">Tienda</a>
        <a routerLink="/contacto" routerLinkActive="text-blue-600" class="text-gray-700 hover:text-blue-600 transition-colors font-medium">Contacto</a>
      </div>

      <div class="hidden lg:block">
        <a routerLink="/el-futuro-es-ahora" class="inline-block px-6 py-3 bg-blue-600 text-white font-semibold rounded-full hover:bg-blue-700 hover:-translate-y-0.5 hover:shadow-lg transition-all duration-300">
